"use client";
import { useState } from "react";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
const filters=["Owner","Status","Priority"];
export default function ModularQueryEditor(){const [picked,setPicked]=useState<string[]>([]);const reduced=useReducedMotion();const toggle=(name:string)=>setPicked(v=>v.includes(name)?v.filter(x=>x!==name):[...v,name]);return <form onSubmit={e=>e.preventDefault()} className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label htmlFor="query" className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">query builder</label><div className="mt-3 flex flex-wrap gap-2">{filters.map(name=><motion.button key={name} type="button" aria-pressed={picked.includes(name)} onClick={()=>toggle(name)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} transition={{duration:.18}} className="min-h-11 rounded-xl border border-[#ececee] px-3 text-sm font-bold text-[#111] aria-pressed:border-[#2563eb] aria-pressed:bg-[#eff6ff] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{name}</motion.button>)}</div><div className="mt-4 flex min-h-11 flex-wrap gap-2 rounded-xl bg-[#f4f5f6] p-2"><AnimatePresence>{picked.map(name=><motion.span key={name} initial={{opacity:0,scale:.8}} animate={{opacity:1,scale:1}} exit={{opacity:0,scale:.8}} transition={reduced?{duration:.12}:{type:"spring",stiffness:360,damping:29}} className="rounded-lg bg-[#2563eb] px-2 py-1 text-xs font-bold text-white">{name}</motion.span>)}</AnimatePresence><span className="self-center text-xs text-[#4a4a4f]">{picked.length?`${picked.length} active filters`:"No filters selected"}</span></div><input id="query" aria-label="Search query" placeholder="Search issues" className="mt-3 min-h-11 w-full rounded-xl border border-[#ececee] px-3 text-sm outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"/><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{picked.length} filters included in this query.</p></form>}
